1	-- ─── Fix 1: Add notifications to the Realtime publication ────────────────────
2	-- Without this line the postgres_changes subscription in use-notifications.ts
3	-- is completely silent — events are never emitted, so the bell badge only
4	-- updates after a full page refresh.
5	
6	ALTER PUBLICATION supabase_realtime ADD TABLE public.notifications;
7	
