9	-- ─── Fix 2: Notify for ALL message types, not just text ───────────────────────
10	-- The original trigger skipped file / voice / invoice / contract messages,
11	-- so those chat messages produced no notification at all.
12	
13	CREATE OR REPLACE FUNCTION public.notify_chat_message()
14	RETURNS TRIGGER
15	LANGUAGE plpgsql
16	SECURITY DEFINER
17	SET search_path = public
18	AS $$
19	DECLARE
20	  v_member_id   uuid;
21	  v_sender_name text;
22	  v_existing_id uuid;
23	  v_title       text;
24	  v_body        text;
25	BEGIN
26	  -- Derive a human-readable title/body based on message type.
27	  SELECT COALESCE(display_name, handle, 'Someone')
28	  INTO   v_sender_name
29	  FROM   public.profiles
30	  WHERE  id = NEW.sender_id;
31	
32	  CASE NEW.message_type
33	    WHEN 'text'     THEN
34	      v_title := v_sender_name || ' sent you a message';
35	      v_body  := CASE
36	                   WHEN NEW.is_encrypted THEN '🔒 Encrypted message'
37	                   ELSE LEFT(COALESCE(NEW.content, ''), 120)
38	                 END;
39	    WHEN 'voice'    THEN
40	      v_title := v_sender_name || ' sent a voice note';
41	      v_body  := '🎤 Voice note';
42	    WHEN 'file'     THEN
43	      v_title := v_sender_name || ' sent a file';
44	      v_body  := '📎 ' || COALESCE(NEW.file_name, 'Attachment');
45	    WHEN 'invoice'  THEN
46	      v_title := v_sender_name || ' sent an invoice';
47	      v_body  := '🧾 Invoice attached';
48	    WHEN 'contract' THEN
49	      v_title := v_sender_name || ' sent a contract';
50	      v_body  := '📋 Contract attached';
51	    ELSE
52	      -- workspace_invite and any future types — skip silently.
53	      RETURN NEW;
54	  END CASE;
55	
56	  FOR v_member_id IN
57	    SELECT user_id
58	    FROM   public.chat_room_members
59	    WHERE  room_id = NEW.room_id
60	      AND  user_id != NEW.sender_id
61	  LOOP
62	    -- Look for an existing unread notification for the same room within 30 min.
63	    SELECT id INTO v_existing_id
64	    FROM   public.notifications
65	    WHERE  user_id = v_member_id
66	      AND  type    = 'message'
67	      AND  (data->>'room_id') = NEW.room_id::text
68	      AND  read    = false
69	      AND  created_at > now() - interval '30 minutes'
70	    LIMIT 1;
71	
72	    IF v_existing_id IS NOT NULL THEN
73	      -- Bump the existing notification so it surfaces at the top.
74	      UPDATE public.notifications
75	      SET    title      = v_sender_name || ' sent more messages',
76	             body       = v_body,
77	             created_at = now()
78	      WHERE  id = v_existing_id;
79	    ELSE
80	      INSERT INTO public.notifications (user_id, type, title, body, data)
81	      VALUES (v_member_id, 'message', v_title, v_body,
82	              jsonb_build_object('room_id', NEW.room_id::text));
83	    END IF;
84	  END LOOP;
85	
86	  RETURN NEW;
87	END;
88	$$;
